Part.Source:
&CreDtaVct = serverdate()

For Each Order EmpCod, FilCod, CreCod
	Where EmpCod = &EmpCod
	Where CreCarBanCod = &BanCarCod
	Where CreFrpPgtoTip = TipoDUplicata.CARTAOD or CreFrpPgtoTip = TipoDuplicata.CARTAOC
	Where CreSts <> Status_Duplicata.CANCELADA
	Where CreDtaVct <= &CreDtaVct
	Where CreVlrSdo > 0

	//	if CreVlrSdo > 0 and &ZoopTax > 0
	//		CreCarTax = (&ZoopTax / CreVlrSdo) * 100
	//		CreCarTax = &CreCarTax
	//	Endif

	//	if &ZoopTip = 'D'
	//		CreCarCreDeb = 1 //DEBITO
	//	Else
	//		CreCarCreDeb = 2 //CREDITO
	//	Endif

	//	if not &DataPagamento.IsEmpty()
	//		CreDtaVct = &DataPagamento
	//	Else
	//		&DataPagamento = CreDtaVct
	//	Endif
	//	CreCarArqc = &zoopEvent.installment
	//	if not &AuxzoopEvent.payment_method.card_brand.IsEmpty()
	//		CreCarBanNom = &AuxzoopEvent.payment_method.card_brand
	//		CreCarCardNom = &AuxzoopEvent.payment_method.holder_name
	//	Endif

	//	Commit

	//	if CreVlrSdo <= 0
	//		&IsBaixou = true
	//		Exit
	//	Endif
	&ZoopTax = 0
	if CreCarTax > 0 and CreVlrSdo > 0 
		&ZoopTax = CreVlrSdo * (CreCarTax/100)
	EndiF

	if CreVlrSdo = CreVlrDup and CreVlrSdo > 0
		&SdtPagamentoDuplicata.Clear()

		&SdtPagamentoDuplicataItem = new()
		&SdtPagamentoDuplicataItem.CreCod    = CreCod
		&SdtPagamentoDuplicataItem.FilCod    = FilCod   
		&SdtPagamentoDuplicataItem.CreCliCod = CreCliCod
		&SdtPagamentoDuplicataItem.CreCliRaz = CreCliRaz
		&SdtPagamentoDuplicataItem.CreCliCodRaz = Trim(str(CreCliCod))+'-'+trim(CreCliRaz)
		&SdtPagamentoDuplicataItem.CreVlrPgt = CreVlrSdo
		&SdtPagamentoDuplicataItem.CreVlrSdo = CreVlrSdo
		&SdtPagamentoDuplicataItem.CreCbrCod = CreCbrCod
		&SdtPagamentoDuplicataItem.CrePedCod = CrePedCod
		&SdtPagamentoDuplicataItem.CreDupNro = CreDupNro
		&SdtPagamentoDuplicataItem.CreDtaEms = CreDtaEms
		&SdtPagamentoDuplicataItem.CreDtaVct = CreDtaVct
		&SdtPagamentoDuplicataItem.CrePagDta = CreDtaVct
		&SdtPagamentoDuplicataItem.CreEnvSpc = CreEnvSpc
		&sdtPagamentoDuplicataItem.MovCpl    = 'CL:' + trim(str(CreCliCod)) + ' - ' + trim(CreCliRaz)
		&SdtPagamentoDuplicataItem.CreSts    = CreSts	
		&SdtPagamentoDuplicataItem.Mensagem  = 'CL:' + trim(str(CreCliCod)) + ' - ' + trim(CreCliRaz)
		&SdtPagamentoDuplicataItem.CreTipBxa = TipoDuplicataBaixa.Total
		&SdtPagamentoDuplicataItem.CrePagVlrTar = &ZoopTax
		&SdtPagamentoDuplicataItem.CrePlanCod = CrePlanCod
		&SdtPagamentoDuplicataItem.CreCarBanCod = CreCarBanCod
		&SdtPagamentoDuplicataItem.CreCarCreDeb = CreCarCreDeb
		&SdtPagamentoDuplicataItem.CreCarTax = CreCarTax
		&SdtPagamentoDuplicata.Add(&SdtPagamentoDuplicataItem)		

		GravaFinanceiroDuplicataCartao.Call(EmpCod, CreDtaVct, CreVlrSdo, false, &SdtPagamentoDuplicata)

		&CreCobObs = '#LIQUIDACAO AUTOMATICA NO VENCIMENTO JASPI#'
		GravaCObranca.Call(EmpCod, FilCod, CreCod, &CreCobObs, 0,0, serverdate() ,'', TipoObservacaoDuplicata.INTERNA)
	Endif
EndFor
